import React, { useEffect, useMemo, useState } from 'react'

/** ======= Utils ======= */
const LS_KEYS = {
    customers: 'cc_customers',
    contracts: 'cc_contracts',
    payments:  'cc_payments',
    events:    'cc_events',
    activity:  'cc_activity',
    role:      'cc_role'
}

const fmtMoney = (n) => (Number(n || 0)).toLocaleString('vi-VN') + '₫'
const todayStr = () => new Date().toISOString().slice(0,10)
const addDaysStr = (n) => { const d=new Date(); d.setDate(d.getDate()+n); return d.toISOString().slice(0,10) }

const seedData = () => ({
    customers: [
        {id:'c1', name:'Nguyễn Văn A', org:'Công ty XD An Phát', phone:'0901 234 567', email:'a@anphat.vn', address:'Q.1, HCM', owner:'Trần Minh', group:'VIP', industry:'Nhà ở', region:'HCM'},
        {id:'c2', name:'Lê Thị B',   org:'BĐS Miền Trung',      phone:'0902 345 678', email:'b@bdsmientrung.vn', address:'TP. Đà Nẵng', owner:'Lan Anh', group:'Tiềm năng', industry:'BĐS', region:'Miền Trung'},
    ],
    contracts: [
        {id:'ct1', code:'HD-2024-001', customerId:'c1', value:1200000000, signDate: todayStr(), dueDate: addDaysStr(90), type:'Thi công', status:'Đang thực hiện', note:'Thi công khu A'},
        {id:'ct2', code:'HD-2024-002', customerId:'c2', value:450000000,  signDate: todayStr(), dueDate: addDaysStr(60), type:'Thiết kế', status:'Đang thực hiện', note:''},
    ],
    payments: [
        {id:'p1', contractId:'ct1', date: todayStr(), amount:300000000, method:'Chuyển khoản', confirmer:'Kế toán Hương', note:'Đợt 1'},
    ],
    events: [
        {id:'e1', title:'Hẹn gặp KH A', type:'Lịch hẹn', date:addDaysStr(2), time:'09:00', customerId:'c1', contractId:'',   assignee:'Trần Minh',    reminder:true},
        {id:'e2', title:'Nhắc thanh toán KH A', type:'Nhắc thanh toán', date:addDaysStr(7), time:'10:00', customerId:'c1', contractId:'ct1', assignee:'Kế toán Hương', reminder:true},
    ],
    activity: [],
    role: 'admin',
})

/** ======= CSV helpers ======= */
const toCSV = (rowsObjArray) => {
    if (!rowsObjArray?.length) return ''
    const keys = Object.keys(rowsObjArray[0])
    const esc = (v) => `"${String(v ?? '').replace(/"/g, '""')}"`
    const lines = [
        keys.map(esc).join(','),
        ...rowsObjArray.map(o => keys.map(k => esc(o[k])).join(','))
    ]
    return lines.join('\n')
}

const download = (name, content, type='text/csv;charset=utf-8;') => {
    const blob = new Blob([content], {type})
    const url = URL.createObjectURL(blob)
    const a = document.createElement('a')
    a.href = url
    a.download = name
    a.click()
    setTimeout(()=> URL.revokeObjectURL(url), 500)
}

/** ======= Tiny presentational helpers ======= */
const Badge = ({children, className=''}) =>
    <span className={`badge ${className}`}>{children}</span>

/** ======= Modals ======= */
function Modal({ open, onClose, title, children, footer }) {
    if (!open) return null
    return (
        <div className="fixed inset-0 z-50">
            <div className="absolute inset-0 bg-black/50" onClick={onClose} />
            <div className="relative max-w-3xl mx-auto mt-10 glass rounded-2xl border border-white/10 p-5">
                <div className="flex items-center justify-between">
                    <h3 className="text-xl font-extrabold">{title}</h3>
                    <button onClick={onClose} className="bg-white/10 hover:bg-white/20 border border-white/10 rounded-lg px-3 py-1.5">Đóng</button>
                </div>
                <div className="mt-4">{children}</div>
                <div className="flex items-center justify-end gap-2 mt-5">
                    {footer}
                </div>
            </div>
        </div>
    )
}

/** ======= App ======= */
export default function App() {
    /** ---- State ---- */
    const [customers, setCustomers] = useState([])
    const [contracts, setContracts] = useState([])
    const [payments,  setPayments]  = useState([])
    const [events,    setEvents]    = useState([])
    const [activity,  setActivity]  = useState([])
    const [role,      setRole]      = useState('admin')

    const [tab, setTab] = useState('dashboard')

    // Filters
    const [globalQ, setGlobalQ] = useState('')
    const [customerFilter, setCustomerFilter] = useState({ q:'', group:'', region:'', industry:'' })
    const [contractFilter, setContractFilter] = useState({ q:'', status:'', type:'' })
    const [eventFilter,    setEventFilter]    = useState({ q:'', type:'', time:'' })
    const [paymentContractId, setPaymentContractId] = useState('')

    // Modals & edited item ids
    const [showCustomerModal, setShowCustomerModal] = useState(false)
    const [editCustomerId, setEditCustomerId] = useState(null)

    const [showContractModal, setShowContractModal] = useState(false)
    const [editContractId, setEditContractId] = useState(null)

    const [showPaymentModal, setShowPaymentModal] = useState(false)
    const [editPaymentId, setEditPaymentId] = useState(null)

    const [showEventModal, setShowEventModal] = useState(false)
    const [editEventId, setEditEventId] = useState(null)

    // Notifications & Toast
    const [notifOpen, setNotifOpen] = useState(false)
    const [toast, setToast] = useState({ open:false, msg:'', type:'success' })
    const openToast = (msg, type='success') => {
        setToast({open:true, msg, type})
        setTimeout(()=> setToast(t => ({...t, open:false})), 2200)
    }

    /** ---- Load from localStorage once ---- */
    useEffect(() => {
        const rawC = localStorage.getItem(LS_KEYS.customers)
        const rawCt= localStorage.getItem(LS_KEYS.contracts)
        const rawP = localStorage.getItem(LS_KEYS.payments)
        const rawE = localStorage.getItem(LS_KEYS.events)
        const rawA = localStorage.getItem(LS_KEYS.activity)
        const rawR = localStorage.getItem(LS_KEYS.role)

        if (rawC && rawCt && rawP && rawE) {
            try {
                setCustomers(JSON.parse(rawC))
                setContracts(JSON.parse(rawCt))
                setPayments(JSON.parse(rawP))
                setEvents(JSON.parse(rawE))
                setActivity(rawA ? JSON.parse(rawA) : [])
                setRole(rawR || 'admin')
            } catch {
                const s = seedData()
                setCustomers(s.customers); setContracts(s.contracts); setPayments(s.payments); setEvents(s.events)
                setActivity([]); setRole('admin')
                persistAll(s.customers, s.contracts, s.payments, s.events, [], 'admin')
            }
        } else {
            const s = seedData()
            setCustomers(s.customers); setContracts(s.contracts); setPayments(s.payments); setEvents(s.events)
            setActivity([]); setRole('admin')
            persistAll(s.customers, s.contracts, s.payments, s.events, [], 'admin')
        }
    }, [])

    /** ---- Persist on changes ---- */
    useEffect(() => { localStorage.setItem(LS_KEYS.customers, JSON.stringify(customers)) }, [customers])
    useEffect(() => { localStorage.setItem(LS_KEYS.contracts, JSON.stringify(contracts)) }, [contracts])
    useEffect(() => { localStorage.setItem(LS_KEYS.payments,  JSON.stringify(payments))  }, [payments])
    useEffect(() => { localStorage.setItem(LS_KEYS.events,    JSON.stringify(events))    }, [events])
    useEffect(() => { localStorage.setItem(LS_KEYS.activity,  JSON.stringify(activity))  }, [activity])
    useEffect(() => { localStorage.setItem(LS_KEYS.role, role) }, [role])

    const persistAll = (cs, cts, ps, es, acts, r) => {
        localStorage.setItem(LS_KEYS.customers, JSON.stringify(cs))
        localStorage.setItem(LS_KEYS.contracts, JSON.stringify(cts))
        localStorage.setItem(LS_KEYS.payments,  JSON.stringify(ps))
        localStorage.setItem(LS_KEYS.events,    JSON.stringify(es))
        localStorage.setItem(LS_KEYS.activity,  JSON.stringify(acts))
        localStorage.setItem(LS_KEYS.role,      r)
    }

    /** ---- Derived helpers ---- */
    const findCustomer = (id) => customers.find(c => c.id === id)
    const findContract = (id) => contracts.find(c => c.id === id)
    const sumPaidByContract = (contractId) =>
        payments.filter(p => p.contractId === contractId).reduce((s,p)=> s + Number(p.amount||0), 0)

    const pushActivity = (text) => {
        const entry = { id: crypto.randomUUID(), time: new Date().toLocaleString('vi-VN'), text, role }
        setActivity(prev => [entry, ...prev])
    }

    /** ---- Notifications ---- */
    const notifItems = useMemo(() => {
        const now = new Date()
        const items = []
        events.forEach(e => {
            if (!e.reminder) return
            const t = new Date(`${e.date}T${e.time||'00:00'}`)
            if (t <= now) {
                const c = findCustomer(e.customerId)
                items.push({ id:`ne-${e.id}`, text: `${e.title} • ${c?.name||''} (${e.date} ${e.time||''})` })
            }
        })
        contracts.forEach(ct => {
            const due = new Date(`${ct.dueDate}T00:00`)
            const remain = (ct.value||0) - sumPaidByContract(ct.id)
            if (due <= now && remain > 0) {
                items.push({ id:`nd-${ct.id}`, text: `Tới hạn thanh toán ${ct.code} • Còn: ${fmtMoney(remain)}` })
            }
        })
        return items
    }, [events, contracts, payments, customers])

    /** ---- Dashboard figures ---- */
    const dashboard = useMemo(() => {
        const active = contracts.filter(ct => ct.status === 'Đang thực hiện').length
        const totalPaid = contracts.reduce((s, ct) => s + sumPaidByContract(ct.id), 0)
        return {
            customerCount: customers.length,
            activeContracts: active,
            totalPaid,
            dueCount: notifItems.length
        }
    }, [customers, contracts, payments, notifItems])

    /** ---- Global search ---- */
    const globalResults = useMemo(() => {
        const q = globalQ.trim().toLowerCase()
        if (!q) return []
        const out = []
        customers.forEach(c => {
            const hay = [c.name,c.org,c.email,c.phone,c.owner,c.industry,c.region,c.group].join(' ').toLowerCase()
            if (hay.includes(q)) out.push({type:'Khách hàng', title:c.name, sub:c.org, badge:c.group})
        })
        contracts.forEach(ct => {
            const c = findCustomer(ct.customerId)
            const hay = [ct.code, c?.name, ct.type, ct.status].join(' ').toLowerCase()
            if (hay.includes(q)) out.push({type:'Hợp đồng', title:ct.code, sub:c?.name||'', badge:ct.status})
        })
        return out
    }, [globalQ, customers, contracts])

    /** ---- Customers tab filtered ---- */
    const customersView = useMemo(() => {
        const { q, group, region, industry } = customerFilter
        const ql = q.trim().toLowerCase()
        return customers.filter(c => {
            const okQ = !ql || [c.name,c.org,c.email,c.phone,c.owner,c.region,c.industry].join(' ').toLowerCase().includes(ql)
            const okG = !group || c.group === group
            const okR = !region || (c.region||'').toLowerCase().includes(region.trim().toLowerCase())
            const okI = !industry || (c.industry||'').toLowerCase().includes(industry.trim().toLowerCase())
            return okQ && okG && okR && okI
        })
    }, [customers, customerFilter])

    /** ---- Contracts tab filtered ---- */
    const contractsView = useMemo(() => {
        const { q, status, type } = contractFilter
        const ql = q.trim().toLowerCase()
        return contracts.filter(ct => {
            const c = findCustomer(ct.customerId)
            const okQ = !ql || [ct.code, c?.name, ct.type, ct.status].join(' ').toLowerCase().includes(ql)
            const okS = !status || ct.status === status
            const okT = !type   || ct.type === type
            return okQ && okS && okT
        })
    }, [contracts, contractFilter, customers])

    /** ---- Payments view for selected contract ---- */
    useEffect(() => {
        if (!paymentContractId && contracts.length) setPaymentContractId(contracts[0].id)
    }, [contracts, paymentContractId])

    const paymentSummary = useMemo(() => {
        if (!paymentContractId) return { value:0, paid:0, remain:0, pct:0 }
        const ct = findContract(paymentContractId)
        const paid = sumPaidByContract(paymentContractId)
        const value = ct?.value || 0
        const remain = Math.max(0, value - paid)
        const pct = value ? Math.min(100, Math.round(paid/value*100)) : 0
        return { value, paid, remain, pct, code: ct?.code }
    }, [paymentContractId, contracts, payments])

    const paymentsView = useMemo(() => {
        return payments.filter(p => p.contractId === paymentContractId)
    }, [payments, paymentContractId])

    /** ---- Events filtered ---- */
    const eventsView = useMemo(() => {
        const { q, type, time } = eventFilter
        const ql = q.trim().toLowerCase()
        const now = new Date()
        return events.filter(e => {
            const okQ = !ql || [e.title, e.assignee].join(' ').toLowerCase().includes(ql)
            const okT = !type || e.type === type
            const eDate = new Date(`${e.date}T${e.time||'00:00'}`)
            let okTime = true
            if (time === 'upcoming') okTime = eDate > now
            if (time === 'overdue')  okTime = eDate < now
            if (time === 'today')    okTime = e.date === todayStr()
            return okQ && okT && okTime
        })
    }, [events, eventFilter])

    /** ---- Upcoming (7 days) ---- */
    const upcoming = useMemo(() => {
        const now = new Date()
        const next7 = new Date(); next7.setDate(now.getDate() + 7)
        const items = []
        // events
        events.forEach(e => {
            const t = new Date(`${e.date}T${e.time||'00:00'}`)
            if (t >= now && t <= next7) {
                const c = findCustomer(e.customerId)
                items.push({
                    when: t,
                    key: `ue-${e.id}`,
                    html: (
                        <div className="flex items-start gap-3">
                            <div className="h-8 w-8 rounded-lg bg-white/10 flex items-center justify-center">
                                <svg width="18" height="18" viewBox="0 0 24 24" fill="none">
                                    <path d="M6 2v4M18 2v4M3 10h18M5 6h14a2 2 0 012 2v10a2 2 0 01-2 2H5a2 2 0 01-2-2V8a2 2 0 012-2z" stroke="white" strokeWidth="1.5"/>
                                </svg>
                            </div>
                            <div>
                                <div className="font-semibold">{e.title}</div>
                                <div className="text-sm text-slate-300">{e.date} • {e.time||'—'} • {c?.name||''}</div>
                            </div>
                        </div>
                    )
                })
            }
        })
        // contracts due
        contracts.forEach(ct => {
            const due = new Date(`${ct.dueDate}T00:00`)
            if (due >= now && due <= next7) {
                const paid = sumPaidByContract(ct.id)
                if (paid < (ct.value||0)) {
                    items.push({
                        when: due,
                        key: `ud-${ct.id}`,
                        html: (
                            <div className="flex items-start gap-3">
                                <div className="h-8 w-8 rounded-lg bg-amber-500/30 flex items-center justify-center">
                                    <svg width="18" height="18" viewBox="0 0 24 24" fill="none">
                                        <path d="M12 9v4m0 4h.01M10.29 3.86L1.82 18a2 2 0 001.71 3h16.94a2 2 0 001.71-3L13.71 3.86a2 2 0 00-3.42 0z" stroke="white" strokeWidth="1.5"/>
                                    </svg>
                                </div>
                                <div>
                                    <div className="font-semibold">Tới hạn thanh toán • {ct.code}</div>
                                    <div className="text-sm text-slate-300">{ct.dueDate} • Còn: {fmtMoney((ct.value||0)-paid)}</div>
                                </div>
                            </div>
                        )
                    })
                }
            }
        })
        return items.sort((a,b)=> a.when - b.when).slice(0,5)
    }, [events, contracts, payments, customers])

    /** ---- CRUD handlers: Customers ---- */
    const openCustomerModal = (id=null) => { setEditCustomerId(id); setShowCustomerModal(true) }
    const upsertCustomer = (payload) => {
        if (!payload.name?.trim()) return openToast('Vui lòng nhập tên khách hàng', 'error')
        if (editCustomerId) {
            setCustomers(prev => prev.map(c => c.id === editCustomerId ? {...c, ...payload} : c))
            pushActivity(`Cập nhật khách hàng: ${payload.name}`)
        } else {
            const id = crypto.randomUUID()
            setCustomers(prev => [{id, ...payload}, ...prev])
            pushActivity(`Thêm khách hàng: ${payload.name}`)
        }
        setShowCustomerModal(false); setEditCustomerId(null); openToast('Đã lưu khách hàng')
    }
    const deleteCustomer = (id) => {
        const c = findCustomer(id)
        if (!confirm(`Xoá khách hàng "${c?.name}" và các liên kết?`)) return
        const contractIds = contracts.filter(ct => ct.customerId===id).map(ct => ct.id)
        setContracts(prev => prev.filter(ct => ct.customerId!==id))
        setPayments(prev  => prev.filter(p => !contractIds.includes(p.contractId)))
        setEvents(prev    => prev.filter(e => e.customerId!==id))
        setCustomers(prev => prev.filter(x => x.id!==id))
        pushActivity(`Xoá khách hàng: ${c?.name}`); openToast('Đã xoá khách hàng','warn')
    }

    /** ---- CRUD: Contracts ---- */
    const openContractModal = (id=null) => { setEditContractId(id); setShowContractModal(true) }
    const upsertContract = (payload) => {
        if (!payload.code?.trim()) return openToast('Vui lòng nhập mã hợp đồng','error')
        if (editContractId) {
            setContracts(prev => prev.map(ct => ct.id===editContractId ? {...ct, ...payload} : ct))
            pushActivity(`Cập nhật hợp đồng: ${payload.code}`)
        } else {
            const id = crypto.randomUUID()
            setContracts(prev => [{id, ...payload}, ...prev])
            pushActivity(`Thêm hợp đồng: ${payload.code}`)
        }
        setShowContractModal(false); setEditContractId(null); openToast('Đã lưu hợp đồng')
    }
    const deleteContract = (id) => {
        const ct = findContract(id)
        if (!confirm(`Xoá hợp đồng "${ct?.code}" và các đợt thanh toán liên quan?`)) return
        setPayments(prev => prev.filter(p => p.contractId !== id))
        setEvents(prev   => prev.filter(e => e.contractId !== id))
        setContracts(prev=> prev.filter(x => x.id !== id))
        pushActivity(`Xoá hợp đồng: ${ct?.code}`); openToast('Đã xoá hợp đồng','warn')
    }

    /** ---- CRUD: Payments ---- */
    const openPaymentModal = (id=null) => { setEditPaymentId(id); setShowPaymentModal(true) }
    const upsertPayment = (payload) => {
        if (!paymentContractId) return openToast('Chưa chọn hợp đồng', 'error')
        if (!Number(payload.amount||0)) return openToast('Số tiền không hợp lệ','error')
        const record = { contractId: paymentContractId, ...payload }
        if (editPaymentId) {
            setPayments(prev => prev.map(p => p.id===editPaymentId ? {...p, ...record} : p))
            pushActivity(`Cập nhật đợt thanh toán HĐ ${findContract(paymentContractId)?.code}`)
        } else {
            const id = crypto.randomUUID()
            setPayments(prev => [{id, ...record}, ...prev])
            pushActivity(`Thêm đợt thanh toán HĐ ${findContract(paymentContractId)?.code}`)
        }
        setShowPaymentModal(false); setEditPaymentId(null); openToast('Đã lưu thanh toán')
    }
    const deletePayment = (id) => {
        if (!confirm('Xoá đợt thanh toán này?')) return
        setPayments(prev => prev.filter(x => x.id !== id))
        pushActivity('Xoá đợt thanh toán'); openToast('Đã xoá thanh toán','warn')
    }

    /** ---- CRUD: Events ---- */
    const openEventModal = (id=null) => { setEditEventId(id); setShowEventModal(true) }
    const upsertEvent = (payload) => {
        if (!payload.title?.trim()) return openToast('Vui lòng nhập tiêu đề','error')
        if (editEventId) {
            setEvents(prev => prev.map(e => e.id===editEventId ? {...e, ...payload} : e))
            pushActivity(`Cập nhật sự kiện: ${payload.title}`)
        } else {
            const id = crypto.randomUUID()
            setEvents(prev => [{id, ...payload}, ...prev])
            pushActivity(`Thêm sự kiện: ${payload.title}`)
        }
        setShowEventModal(false); setEditEventId(null); openToast('Đã lưu sự kiện')
    }
    const deleteEvent = (id) => {
        if (!confirm('Xoá sự kiện này?')) return
        const e = events.find(x=>x.id===id)
        setEvents(prev => prev.filter(x => x.id !== id))
        pushActivity(`Xoá sự kiện: ${e?.title}`); openToast('Đã xoá sự kiện','warn')
    }

    /** ---- Reports ---- */
    const reports = useMemo(() => {
        const agg = customers.map(c => {
            const cts = contracts.filter(ct => ct.customerId===c.id)
            const total = cts.reduce((s,ct)=> s + (ct.value||0), 0)
            const paid  = cts.reduce((s,ct)=> s + sumPaidByContract(ct.id), 0)
            return { id:c.id, name:c.name, total, paid, remain: Math.max(0,total-paid) }
        }).filter(x=>x.total>0)

        const max = Math.max(1, ...agg.map(x=>x.total))
        const top = agg.slice().sort((a,b)=> b.total - a.total)[0]
        const grandTotal = agg.reduce((s,d)=> s + d.total, 0)
        const grandPaid  = agg.reduce((s,d)=> s + d.paid,  0)
        return {
            rows: agg,
            max,
            topCustomer: top ? `${top.name} • ${fmtMoney(top.total)}` : '—',
            collectionRate: grandTotal ? Math.round(grandPaid/grandTotal*100) + '%' : '—',
            doneContracts: contracts.filter(ct => ct.status==='Đã hoàn tất').length
        }
    }, [customers, contracts, payments])

    /** ---- Export buttons ---- */
    const exportCustomers = () => {
        if (!customers.length) return openToast('Không có dữ liệu','warn')
        const rows = customers.map(c => ({
            id:c.id, name:c.name, org:c.org, phone:c.phone, email:c.email, address:c.address, owner:c.owner, group:c.group, industry:c.industry, region:c.region
        }))
        download('customers.csv', toCSV(rows))
    }
    const exportContracts = () => {
        if (!contracts.length) return openToast('Không có dữ liệu','warn')
        const rows = contracts.map(ct => ({
            id:ct.id, code:ct.code, customer: findCustomer(ct.customerId)?.name||'', value:ct.value,
            signDate:ct.signDate, dueDate:ct.dueDate, type:ct.type, status:ct.status, note:ct.note
        }))
        download('contracts.csv', toCSV(rows))
    }
    const exportPayments = () => {
        if (!payments.length) return openToast('Không có dữ liệu','warn')
        const rows = payments.map(p => ({
            id:p.id, contract: findContract(p.contractId)?.code||'', date:p.date, amount:p.amount, method:p.method, confirmer:p.confirmer, note:p.note
        }))
        download('payments.csv', toCSV(rows))
    }

    /** ---- Small inputs state for modals ---- */
    const customerEditing = customers.find(c=>c.id===editCustomerId)
    const contractEditing = contracts.find(c=>c.id===editContractId)
    const paymentEditing  = payments.find(p=>p.id===editPaymentId)
    const eventEditing    = events.find(e=>e.id===editEventId)

    /** ---- Render ---- */
    return (
        <div className="min-h-screen flex flex-col">
            {/* Header */}
            <header className="w-full sticky top-0 z-40">
                <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4">
                    <div className="glass rounded-2xl border border-white/10 px-4 py-3 sm:p-4 flex items-center justify-between">
                        <div className="flex items-center gap-3">
                            <div className="h-10 w-10 rounded-xl bg-gradient-to-br from-blue-400 to-emerald-400 flex items-center justify-center shadow-lg">
                                <svg width="22" height="22" viewBox="0 0 24 24" fill="none">
                                    <path d="M3 7l9-4 9 4-9 4-9-4z" stroke="white" strokeWidth="1.5" strokeLinejoin="round"/>
                                    <path d="M3 12l9 4 9-4" stroke="white" strokeWidth="1.5" strokeLinejoin="round"/>
                                    <path d="M3 17l9 4 9-4" stroke="white" strokeWidth="1.5" strokeLinejoin="round"/>
                                </svg>
                            </div>
                            <div>
                                <h1 className="text-lg sm:text-xl font-extrabold tracking-tight">Quản lý Khách hàng & Hợp đồng</h1>
                                <p className="text-xs sm:text-sm text-slate-300/80">Demo giao diện • Phòng Kinh doanh, Kế toán & Hành chính</p>
                            </div>
                        </div>
                        <div className="flex items-center gap-3">
                            <button onClick={()=> setNotifOpen(o=>!o)} className="relative rounded-xl bg-white/10 hover:bg-white/20 border border-white/10 p-2 transition">
                                <svg className="w-6 h-6 text-white/90" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                    <path strokeWidth="1.5" d="M14 18.5a2 2 0 1 1-4 0m10-1.5H4l2-3v-3a6 6 0 1 1 12 0v3l2 3z"/>
                                </svg>
                                {notifItems.length>0 && (
                                    <span className="absolute -top-1 -right-1 bg-rose-500 text-white text-[10px] px-1.5 py-0.5 rounded-full font-bold">
                    {notifItems.length}
                  </span>
                                )}
                            </button>
                            <div className="hidden md:flex items-center gap-2">
                                <button onClick={()=> { setTab('customers'); openCustomerModal(null) }} className="bg-emerald-500 hover:bg-emerald-600 text-white text-sm font-semibold px-3 py-2 rounded-lg shadow">+ Khách hàng</button>
                                <button onClick={()=> { setTab('contracts'); openContractModal(null) }} className="bg-blue-500 hover:bg-blue-600 text-white text-sm font-semibold px-3 py-2 rounded-lg shadow">+ Hợp đồng</button>
                                <button onClick={()=> { setTab('events'); openEventModal(null) }} className="bg-violet-500 hover:bg-violet-600 text-white text-sm font-semibold px-3 py-2 rounded-lg shadow">+ Sự kiện</button>
                            </div>
                        </div>
                    </div>
                </div>
            </header>

            {/* Tabs */}
            <div className="w-full">
                <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
                    <nav className="glass rounded-2xl border border-white/10 p-2 flex flex-wrap gap-2">
                        {['dashboard','customers','contracts','payments','events','reports','activity'].map(t => (
                            <button key={t}
                                    onClick={()=> setTab(t)}
                                    className={`tab-btn px-4 py-2 rounded-xl text-sm font-semibold border border-white/10 ${tab===t ? 'bg-white/15' : 'hover:bg-white/10'}`}>
                                {{
                                    dashboard:'Tổng quan', customers:'Khách hàng', contracts:'Hợp đồng',
                                    payments:'Thanh toán', events:'Sự kiện & Nhắc', reports:'Báo cáo', activity:'Lịch sử'
                                }[t]}
                            </button>
                        ))}
                    </nav>
                </div>
            </div>

            {/* Content */}
            <main className="w-full flex-1 py-6 sm:py-8">
                <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 space-y-6">

                    {/* Dashboard */}
                    {tab==='dashboard' && (
                        <section>
                            <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
