                        )) : <div className="text-slate-300">Không có thông báo</div>}
                    </div>
                </div>
            )}

            {/* Toast */}
            {toast.open && (
                <div className="fixed bottom-6 right-6 z-[60]">
                    <div className="flex items-center gap-3 bg-white/10 border border-white/10 rounded-2xl px-4 py-3">
                        <div className={`h-8 w-8 rounded-xl flex items-center justify-center ${
                            toast.type==='success'?'bg-emerald-500': toast.type==='warn'?'bg-amber-500':'bg-rose-500'
                        }`}>
                            <svg width="18" height="18" viewBox="0 0 24 24" fill="none"><path d="M5 13l4 4L19 7" stroke="white" strokeWidth="2"/></svg>
                        </div>
                        <div className="text-slate-100 font-semibold">{toast.msg}</div>
                        <button onClick={()=>setToast(t=>({...t,open:false}))} className="ml-2 text-slate-300 hover:text-white">Đóng</button>
                    </div>
                </div>
            )}

            {/* Modals */}
            <CustomerModal
                open={showCustomerModal}
                onClose={()=>{ setShowCustomerModal(false); setEditCustomerId(null) }}
                initial={customerEditing}
                onSave={upsertCustomer}
            />
            <ContractModal
                open={showContractModal}
                onClose={()=>{ setShowContractModal(false); setEditContractId(null) }}
                initial={contractEditing}
                customers={customers}
                onSave={upsertContract}
            />
            <PaymentModal
                open={showPaymentModal}
                onClose={()=>{ setShowPaymentModal(false); setEditPaymentId(null) }}
                initial={paymentEditing}
                onSave={upsertPayment}
            />
            <EventModal
                open={showEventModal}
                onClose={()=>{ setShowEventModal(false); setEditEventId(null) }}
                initial={eventEditing}
                customers={customers}
                contracts={contracts}
                onSave={upsertEvent}
            />
        </div>
    )
}

/** ======= Small UI components ======= */
function StatCard({label, badge, badgeClass, value}) {
    return (
        <div className="glass rounded-2xl border border-white/10 p-5">
            <div className="flex items-center justify-between">
                <span className="text-slate-300">{label}</span>
                <Badge className={badgeClass}>{badge}</Badge>
            </div>
            <div className="mt-3 text-3xl font-extrabold">{value}</div>
            <p className="text-sm text-slate-400 mt-1">
                {label === 'Khách hàng' ? 'Tổng số khách hàng'
                    : label === 'Hợp đồng' ? 'Đang thực hiện'
                        : label === 'Đã thanh toán' ? 'Tổng số tiền đã thu'
                            : 'Nhắc thanh toán/sự kiện'}
            </p>
        </div>
    )
}

function Input({label, value, onChange, placeholder}) {
    return (
        <div className="flex-1">
            <label className="block text-sm text-slate-300 mb-1">{label}</label>
            <input value={value} onChange={e=>onChange(e.target.value)}
                   className="w-full bg-white/10 border border-white/10 rounded-xl px-4 py-2.5"
                   placeholder={placeholder} />
        </div>
    )
}

function Select({label, value, onChange, options}) {
    // options: array of string or [value,label]
    const normalized = options.map(o => Array.isArray(o) ? o : [o,o||'Tất cả'])
    return (
        <div>
            <label className="block text-sm text-slate-300 mb-1">{label}</label>
            <select value={value} onChange={e=>onChange(e.target.value)}
                    className="bg-white/10 border border-white/10 rounded-xl px-4 py-2.5">
                {normalized.map(([val, label]) => <option key={val} value={val}>{label}</option>)}
            </select>
        </div>
    )
}

function SummaryCard({label, value, accent}) {
    return (
        <div className="glass rounded-xl border border-white/10 p-4">
            <div className="text-slate-300">{label}</div>
            <div className={`text-2xl font-extrabold mt-1 ${accent||''}`}>{value}</div>
        </div>
    )
}

/** ======= Modal forms ======= */
function CustomerModal({open, onClose, initial, onSave}) {
    const [form, setForm] = useState({
        name:'', org:'', phone:'', email:'', address:'',
        owner:'', group:'VIP', industry:'', region:''
    })
    useEffect(()=> {
        setForm({
            name: initial?.name || '', org: initial?.org || '', phone: initial?.phone || '', email: initial?.email || '',
            address: initial?.address || '', owner: initial?.owner || '', group: initial?.group || 'VIP',
            industry: initial?.industry || '', region: initial?.region || ''
        })
    }, [initial, open])

    return (
        <Modal open={open} onClose={onClose} title={initial?'Sửa khách hàng':'Thêm khách hàng'}
               footer={
                   <>
                       <button onClick={onClose} className="bg-white/10 hover:bg-white/20 border border-white/10 rounded-lg px-4 py-2">Huỷ</button>
                       <button onClick={()=>onSave(form)} className="bg-emerald-500 hover:bg-emerald-600 text-white font-semibold px-4 py-2 rounded-lg">Lưu</button>
                   </>
               }>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {[
                    ['Tên khách hàng','name'], ['Tổ chức','org'], ['Số điện thoại','phone'], ['Email','email'],
                    ['Địa chỉ','address'], ['Người phụ trách','owner'], ['Ngành nghề','industry'], ['Khu vực','region']
                ].map(([label, key])=>(
                    <div key={key}>
                        <label className="block text-sm text-slate-300 mb-1">{label}</label>
                        <input value={form[key]} onChange={e=>setForm(s=>({...s,[key]:e.target.value}))}
                               className="w-full bg-white/10 border border-white/10 rounded-xl px-4 py-2.5"/>
                    </div>
                ))}
                <div>
                    <label className="block text-sm text-slate-300 mb-1">Nhóm</label>
                    <select value={form.group} onChange={e=>setForm(s=>({...s,group:e.target.value}))}
                            className="w-full bg-white/10 border border-white/10 rounded-xl px-4 py-2.5">
                        {['VIP','Tiềm năng','Thường'].map(g=> <option key={g}>{g}</option>)}
                    </select>
                </div>
            </div>
        </Modal>
    )
}

